            pitfallQuestion: 'Â¿QuÃ© error comÃºn debes evitar al estudiar {topic}?',
            explanationQuestion: 'Resume la idea central que enseÃ±a {module}.',
            explanationAnswerPrefix: 'Idea central:',
            pitfallAnswerPrefix: 'Evita este error:',
