async function handleAuthProviderClick(providerKey, providerLabel) {
    try {
        if (maybeRedirectToPreferredAuthHost()) {
            return;
        }
        if (!providerKey) {
            const message = 'Unsupported social auth provider.';
            setAccountAuthStatus(message, 'error');
            showToast(message, 'warning');
            return;
        }
        if (!hasNeonSyncConfig()) {
            const message = `${providerLabel} sign-in requires the backend auth server.`;
            setAccountAuthStatus(message, 'error');
            showToast(message, 'warning');
            return;
        }

        let providersSnapshot = accountAuthState.oauthProviders;
        if (!providersSnapshot || !Object.keys(providersSnapshot).length) {
            providersSnapshot = await loadAuthProviderAvailability({ silent: true });
        }
        const providerState = accountAuthState.oauthProviders?.[providerKey];
        if (!providerState && (!providersSnapshot || !Object.keys(providersSnapshot).length)) {
            const message = 'Unable to verify social sign-in availability right now. Try again shortly.';
            setAccountAuthStatus(message, 'error');
            showToast(message, 'warning');
            return;
        }
        if (providerState && !providerState.enabled) {
            const reason = Array.isArray(providerState.reasons) && providerState.reasons.length
                ? providerState.reasons[0]
                : `${providerLabel} sign-in is not configured yet.`;
            setAccountAuthStatus(reason, 'error');
            showToast(reason, 'warning');
            return;
        }

        const returnTo = window.location.href;
        const startEndpoint = buildNeonOAuthStartEndpoint(providerKey);
        const redirectUrl = `${startEndpoint}?returnTo=${encodeURIComponent(returnTo)}`;
        setAccountAuthStatus(`Redirecting to ${providerLabel}...`, 'info');
        window.location.assign(redirectUrl);
    } catch (error) {
        const resolvedProviderLabel = String(providerLabel || 'social').trim() || 'social';
        reportAuthUiError(error, `Unable to start ${resolvedProviderLabel} sign-in. Please try again.`);
    }
}

function handleForgotPassword() {
    const emailInput = document.getElementById('account-auth-email');
    const identifier = String(emailInput ? emailInput.value.trim() : '');
    if (!identifier) {
        setAccountAuthFieldError('account-auth-email', 'Enter your email or username first.');
        showToast('Enter your email or username first.', 'warning');
        return;
    }
    openSupportModal();

    const topicInput = document.getElementById('support-topic');
    const messageInput = document.getElementById('support-message');
    const moduleSelect = document.getElementById('support-module');
    const normalizedIdentifier = identifier.toLowerCase();
    const timestamp = new Date().toISOString();

    if (topicInput && !topicInput.value.trim()) {
        topicInput.value = 'Password reset request';
    }
    if (moduleSelect && !moduleSelect.value) {
        moduleSelect.value = 'intro-to-coding';
    }
    if (messageInput && !messageInput.value.trim()) {
        messageInput.value = [
            'Please help reset my account password.',
            `Identifier: ${normalizedIdentifier}`,
            `Submitted from auth modal at: ${timestamp}`
        ].join('\n');
    }

    setAccountAuthStatus('Password reset is handled through Support. Your request form has been prefilled.', 'info');
    showToast('Support form prefilled for password reset.', 'info');
}

function clearOAuthResultFromUrlParams() {
    if (typeof window === 'undefined') return;
    const currentUrl = new URL(window.location.href);
    currentUrl.searchParams.delete('oauth');
    currentUrl.searchParams.delete('oauth_provider');
    currentUrl.searchParams.delete('oauth_error');
    currentUrl.searchParams.delete('oauth_ticket');
    const cleanedUrl = `${currentUrl.pathname}${currentUrl.search}${currentUrl.hash}`;
    window.history.replaceState({}, document.title, cleanedUrl);
}

function consumeOAuthResultFromUrl() {
    if (typeof window === 'undefined') return null;
    const currentUrl = new URL(window.location.href);
    const status = String(currentUrl.searchParams.get('oauth') || '').trim().toLowerCase();
    if (!status) return null;
    const provider = String(currentUrl.searchParams.get('oauth_provider') || '').trim().toLowerCase();
    const errorCode = String(currentUrl.searchParams.get('oauth_error') || '').trim().toLowerCase();
    const ticket = String(currentUrl.searchParams.get('oauth_ticket') || '').trim();
    return { status, provider, errorCode, ticket };
}

function describeOAuthError(errorCode, providerLabel) {
    if (errorCode === 'provider_not_configured') {
        return `${providerLabel} sign-in is not configured yet.`;
    }
    if (errorCode === 'provider_rejected') {
        return `${providerLabel} sign-in was canceled or denied.`;
    }
    if (errorCode === 'invalid_state' || errorCode === 'state_expired' || errorCode === 'provider_mismatch') {
        return 'Social sign-in session expired. Please try again.';
    }
    if (errorCode === 'missing_code' || errorCode === 'authentication_failed') {
        return `${providerLabel} sign-in failed. Try again.`;
    }
    return 'Social sign-in failed. Please try again.';
}

function createDelayPromise(delayMs) {
    const waitMs = Math.max(0, Number(delayMs) || 0);
    return new Promise((resolve) => setTimeout(resolve, waitMs));
}

async function exchangeOAuthTicketForSession(ticket, options = {}) {
    const {
        providerKey = '',
        providerLabel = 'Google',
        silent = true
    } = options;
    const normalizedTicket = String(ticket || '').trim();
    if (!normalizedTicket) {
        return {
            isAuthenticated: false,
            invalidTicket: true,
            error: new Error('Missing OAuth exchange ticket.')
        };
    }
    try {
        const ticketPayload = await neonFetch(getNeonOAuthTicketExchangeEndpoint(), {
            method: 'POST',
            body: JSON.stringify({ ticket: normalizedTicket })
        });
        const appliedSession = applySessionPayloadToAuthState(ticketPayload, {
            source: `${providerLabel} session`,
            defaultProvider: providerKey || 'google',
            rememberSessionToken: true,
            silent
        });
        return {
            isAuthenticated: Boolean(appliedSession?.isAuthenticated),
            invalidTicket: false,
            error: null
        };
    } catch (error) {
        const reason = error instanceof Error ? error.message : String(error);
        const normalizedReason = String(reason || '').toLowerCase();
        const invalidTicket = normalizedReason.includes('ticket expired')
            || normalizedReason.includes('ticket is required')
            || normalizedReason.includes('ticket expired or invalid')
            || (normalizedReason.includes('ticket') && normalizedReason.includes('invalid'));
        return {
            isAuthenticated: false,
            invalidTicket,
            error: error instanceof Error ? error : new Error(String(reason || 'OAuth exchange failed.'))
        };
    }
}

async function exchangeOAuthTicketForSessionWithRetry(ticket, options = {}) {
    const {
        providerKey = '',
        providerLabel = 'Google',
        maxAttempts = OAUTH_TICKET_EXCHANGE_MAX_ATTEMPTS,
        attemptDelayMs = OAUTH_TICKET_EXCHANGE_RETRY_DELAY_MS,
        silent = true
    } = options;
    const totalAttempts = Math.max(1, Number(maxAttempts) || 1);
    let latestResult = {
        isAuthenticated: false,
        invalidTicket: false,
        error: null
    };

    for (let attempt = 0; attempt < totalAttempts; attempt += 1) {
        latestResult = await exchangeOAuthTicketForSession(ticket, {
            providerKey,
            providerLabel,
            silent
        });
        if (latestResult.isAuthenticated) {
            return latestResult;
        }
        if (latestResult.invalidTicket) {
            return latestResult;
        }
        if (attempt < totalAttempts - 1) {
            await createDelayPromise(attemptDelayMs);
        }
    }
    return latestResult;
}

async function handleOAuthResultFromUrl() {
    try {
        const oauthResult = consumeOAuthResultFromUrl();
        if (!oauthResult) return;

        const providerLabel = getAuthProviderLabel(oauthResult.provider);
        const providerKey = normalizeAuthProviderKey(oauthResult.provider);
        if (oauthResult.status === 'success') {
            if (maybeRedirectToApiHostedFrontendForAuth()) {
                return;
            }
            setAccountSessionHydrating(true);
            setAccountAuthStatus(`${providerLabel} sign-in completed. Finalizing secure session...`, 'info');
            if (!hasNeonSyncConfig()) {
                const unavailableMessage = `${providerLabel} sign-in requires the auth server configuration.`;
                setAccountAuthStatus(unavailableMessage, 'error');
                showToast(unavailableMessage, 'warning');
                setAccountSessionHydrating(false);
                clearOAuthResultFromUrlParams();
                return;
            }

            let exchangeResult = null;
            if (oauthResult.ticket) {
                exchangeResult = await exchangeOAuthTicketForSessionWithRetry(oauthResult.ticket, {
                    providerKey,
                    providerLabel,
                    maxAttempts: OAUTH_TICKET_EXCHANGE_MAX_ATTEMPTS,
                    attemptDelayMs: OAUTH_TICKET_EXCHANGE_RETRY_DELAY_MS,
                    silent: true
                });
                if (exchangeResult.isAuthenticated || accountAuthState.isAuthenticated) {
                    setAccountSessionHydrating(false);
                    const successMessage = `${providerLabel} account connected.`;
                    setAccountAuthStatus(successMessage, 'success');
                    showToast(successMessage, 'success');
                    clearOAuthResultFromUrlParams();
                    return;
                }
                if (exchangeResult.error) {
                    const exchangeReason = exchangeResult.error instanceof Error
                        ? exchangeResult.error.message
                        : String(exchangeResult.error);
                    console.warn('OAuth ticket exchange failed:', exchangeReason);
                }
                if (exchangeResult.invalidTicket) {
                    setAccountSessionHydrating(false);
                    const invalidTicketMessage = `${providerLabel} sign-in session expired. Please try again.`;
                    setAccountAuthStatus(invalidTicketMessage, 'error');
                    showToast(invalidTicketMessage, 'warning');
                    clearPendingAuthRecoveryState();
                    clearOAuthResultFromUrlParams();
                    return;
                }
                // Ticket exists but exchange has not succeeded yet. Start fast background recovery immediately.
                const exchangeRetryMessage = isCrossOriginApiRuntime()
                    ? `${providerLabel} sign-in completed, but final session sync is delayed. Retrying now.`
                    : `${providerLabel} sign-in completed, but final session sync is still running. Retrying now.`;
                setAccountAuthStatus(exchangeRetryMessage, 'info');
                setPendingAuthRecoveryState(providerKey, providerLabel, oauthResult.ticket || '');
                runSafeBackgroundTask(runAuthSessionRecoveryProbe({
                    providerKey,
                    providerLabel,
                    ticket: oauthResult.ticket || '',
                    maxAttempts: 120,
                    attemptDelayMs: 1800
                }), 'OAuth session recovery probe');
                setAccountSessionHydrating(false);
                clearOAuthResultFromUrlParams();
                return;
            }

            const verifiedSession = await waitForVerifiedAuthSession({
                maxAttempts: 14,
                attemptDelayMs: 850,
                silent: true
            });
            if (verifiedSession?.isAuthenticated || accountAuthState.isAuthenticated) {
                setAccountProviderState(providerKey, providerLabel);
                clearPendingAuthRecoveryState();
                updateAccountChip();
                refreshAccountPrimaryAuthButton();
                setAccountSessionHydrating(false);
                const successMessage = `${providerLabel} account connected.`;
                setAccountAuthStatus(successMessage, 'success');
                showToast(successMessage, 'success');
                clearOAuthResultFromUrlParams();
                return;
            }

            const syncFailureMessage = isCrossOriginApiRuntime()
                ? `${providerLabel} sign-in completed, but session verification is delayed or blocked. Keeping a background retry running now.`
                : `${providerLabel} sign-in completed, but session verification has not finished yet. Keeping a background retry running now.`;
            setAccountAuthStatus(syncFailureMessage, 'error');
            showToast(syncFailureMessage, 'warning');
            setPendingAuthRecoveryState(providerKey, providerLabel, oauthResult.ticket || '');
            runSafeBackgroundTask(runAuthSessionRecoveryProbe({
                providerKey,
                providerLabel,
                ticket: oauthResult.ticket || '',
                maxAttempts: 90,
                attemptDelayMs: 2000
            }), 'OAuth session recovery probe');
            setAccountSessionHydrating(false);
            clearOAuthResultFromUrlParams();
            return;
        }

        const failureMessage = describeOAuthError(oauthResult.errorCode, providerLabel);
        setAccountSessionHydrating(false);
        setAccountAuthStatus(failureMessage, 'error');
        showToast(failureMessage, 'warning');
        clearOAuthResultFromUrlParams();
    } catch (error) {
        setAccountSessionHydrating(false);
        reportAuthUiError(error, 'Social sign-in completed, but session finalization failed. Please try again.');
    }
}

function getAccountPrimaryAuthLabel() {
    if (accountAuthState.isSessionHydrating && !accountAuthState.isAuthenticated) {
        return getStableTranslation('account.auth.submitChecking');
    }
    if (accountAuthState.isAuthenticated) {
        return getStableTranslation('account.auth.state.sessionActive');
    }
    if (accountAuthState.mode === 'signup') {
        return getStableTranslation('account.auth.submitCreate');
    }
    return getStableTranslation('account.auth.submitLogin');
}

function refreshAccountPrimaryAuthButton() {
    const submitBtn = document.getElementById('account-auth-submit');
    if (!submitBtn) return;
    submitBtn.textContent = getAccountPrimaryAuthLabel();
    const shouldDisable = accountAuthState.inFlight || accountAuthState.isAuthenticated || accountAuthState.isSessionHydrating;
    submitBtn.disabled = shouldDisable;
    submitBtn.setAttribute('aria-disabled', shouldDisable ? 'true' : 'false');
    submitBtn.classList.toggle('opacity-70', shouldDisable);
    submitBtn.classList.toggle('cursor-not-allowed', shouldDisable);
    setAccountAuthModeCopy(accountAuthState.mode === 'signup');
    syncAccountSignupToggleState();
    updateAccountAuthCardLayout();
    updateAccountProfileSummaryUI();
}

function setAccountAuthMode(mode) {
    const requestedMode = mode === 'signup' ? 'signup' : 'login';
    const nextMode = accountAuthState.isAuthenticated && requestedMode === 'signup'
        ? 'login'
        : requestedMode;
    accountAuthState.mode = nextMode;

    const loginTab = document.getElementById('account-auth-login-tab');
    const signupTab = document.getElementById('account-auth-signup-tab');
    const signupUsernameGroup = document.getElementById('account-auth-username-group');
    const confirmGroup = document.getElementById('account-auth-confirm-group');
    const submitBtn = document.getElementById('account-auth-submit');
    const passwordInput = document.getElementById('account-auth-password');
    const confirmInput = document.getElementById('account-auth-confirm');
    const signupUsernameInput = document.getElementById('account-auth-username');
    const rememberCheckbox = document.getElementById('account-auth-remember');

    const isSignup = nextMode === 'signup';

    if (loginTab) {
        loginTab.className = `account-auth-tab px-4 py-2 rounded-lg text-sm font-semibold transition-colors duration-200 ${isSignup ? 'bg-transparent text-slate-300 hover:text-white' : 'bg-violet-500 text-white'}`;
    }
    if (signupTab) {
        signupTab.className = `account-auth-tab px-4 py-2 rounded-lg text-sm font-semibold transition-colors duration-200 ${isSignup ? 'bg-violet-500 text-white' : 'bg-transparent text-slate-300 hover:text-white'}`;
    }

    if (confirmGroup) {
        confirmGroup.classList.toggle('hidden', !isSignup);
    }
    if (signupUsernameGroup) {
        signupUsernameGroup.classList.toggle('hidden', !isSignup);
    }
    if (submitBtn) refreshAccountPrimaryAuthButton();
    if (passwordInput) {
        passwordInput.setAttribute('autocomplete', isSignup ? 'new-password' : 'current-password');
        const toggle = document.getElementById('account-auth-password-toggle');
        updateAuthPasswordToggleState(toggle, passwordInput);
    }
    if (signupUsernameInput) {
        signupUsernameInput.required = isSignup;
        if (isSignup && !signupUsernameInput.value.trim() && accountProfile.username) {
            signupUsernameInput.value = accountProfile.username;
        }
    }
    if (confirmInput && !isSignup) {
        confirmInput.value = '';
    }
    if (confirmInput) {
        const toggle = document.getElementById('account-auth-confirm-toggle');
        updateAuthPasswordToggleState(toggle, confirmInput);
    }
    if (rememberCheckbox && isSignup) {
        rememberCheckbox.checked = false;
    }
    setAccountAuthModeCopy(isSignup);
    syncAccountSignupToggleState();
    updateAccountPasswordStrengthMeter();
    clearAccountAuthValidationState();
}

function clearAuthPasswordFields() {
    const passwordInput = document.getElementById('account-auth-password');
    const confirmInput = document.getElementById('account-auth-confirm');
    if (passwordInput) {
        passwordInput.value = '';
        passwordInput.type = 'password';
    }
    if (confirmInput) {
        confirmInput.value = '';
        confirmInput.type = 'password';
    }
    const passwordToggle = document.getElementById('account-auth-password-toggle');
    const confirmToggle = document.getElementById('account-auth-confirm-toggle');
    updateAuthPasswordToggleState(passwordToggle, passwordInput);
    updateAuthPasswordToggleState(confirmToggle, confirmInput);
    updateAccountPasswordStrengthMeter();
}

function clearAccountAuthValidationState() {
    [
        'account-auth-email',
        'account-auth-username',
        'account-auth-password',
        'account-auth-confirm'
    ].forEach((fieldId) => {
        const input = document.getElementById(fieldId);
        if (!input) return;
        input.classList.remove('is-invalid-field');
        input.removeAttribute('aria-invalid');
    });
}

function setAccountAuthFieldError(fieldId, message) {
    const input = document.getElementById(fieldId);
    if (input) {
        input.classList.add('is-invalid-field');
        input.setAttribute('aria-invalid', 'true');
        input.focus();
    }
    setAccountAuthStatus(message, 'error');
}

function setAuthSubmitBusy(isBusy) {
    accountAuthState.inFlight = Boolean(isBusy);
    const submitBtn = document.getElementById('account-auth-submit');
    const heroLogoutBtn = document.getElementById('account-auth-hero-logout');
    const heroManageBtn = document.getElementById('account-auth-hero-manage');
    const retrySessionButton = document.getElementById('account-auth-retry-session');
    if (submitBtn) {
        const shouldDisableSubmit = accountAuthState.inFlight || accountAuthState.isAuthenticated || accountAuthState.isSessionHydrating;
        submitBtn.disabled = shouldDisableSubmit;
        submitBtn.classList.toggle('opacity-70', shouldDisableSubmit);
        submitBtn.classList.toggle('cursor-not-allowed', shouldDisableSubmit);
        if (accountAuthState.inFlight) {
            if (accountAuthState.mode === 'signup') {
                submitBtn.textContent = getStableTranslation('account.auth.submitCreating');
            } else {
                submitBtn.textContent = accountAuthState.isAuthenticated
                    ? getStableTranslation('account.auth.submitSigningOut')
                    : getStableTranslation('account.auth.submitLoggingIn');
            }
        }
    }
    if (heroLogoutBtn) {
        heroLogoutBtn.disabled = accountAuthState.inFlight;
        heroLogoutBtn.setAttribute('aria-disabled', accountAuthState.inFlight ? 'true' : 'false');
        heroLogoutBtn.textContent = accountAuthState.inFlight
            ? getStableTranslation('account.auth.submitSigningOut')
            : getStableTranslation('account.actions.signOut');
        heroLogoutBtn.classList.toggle('opacity-70', accountAuthState.inFlight);
        heroLogoutBtn.classList.toggle('cursor-not-allowed', accountAuthState.inFlight);
    }
    if (heroManageBtn) {
        heroManageBtn.disabled = accountAuthState.inFlight;
        heroManageBtn.setAttribute('aria-disabled', accountAuthState.inFlight ? 'true' : 'false');
        heroManageBtn.classList.toggle('opacity-70', accountAuthState.inFlight);
        heroManageBtn.classList.toggle('cursor-not-allowed', accountAuthState.inFlight);
    }
    if (retrySessionButton) {
        const disableRetry = accountAuthState.inFlight || (accountAuthState.isSessionHydrating && !accountAuthState.isAuthenticated);
        retrySessionButton.disabled = disableRetry;
        retrySessionButton.setAttribute('aria-disabled', disableRetry ? 'true' : 'false');
        retrySessionButton.classList.toggle('opacity-70', disableRetry);
        retrySessionButton.classList.toggle('cursor-not-allowed', disableRetry);
        retrySessionButton.textContent = accountAuthState.isSessionHydrating && !accountAuthState.isAuthenticated
            ? getStableTranslation('account.auth.submitChecking')
            : getStableTranslation('auth.retrySession');
    }
    if (!accountAuthState.inFlight) {
        refreshAccountPrimaryAuthButton();
    }
}

function readAccountAuthForm() {
    const emailInput = document.getElementById('account-auth-email');
    const passwordInput = document.getElementById('account-auth-password');
    const confirmInput = document.getElementById('account-auth-confirm');
    const usernameInput = document.getElementById('account-auth-username');
    return {
        email: emailInput ? emailInput.value.trim() : '',
        username: usernameInput ? usernameInput.value.trim() : '',
        password: passwordInput ? passwordInput.value : '',
        confirm: confirmInput ? confirmInput.value : ''
    };
}

function getScriptDerivedBasePath() {
    const runtimeResolver = typeof window !== 'undefined'
        ? window.CSAtlasRuntime?.getScriptDerivedBasePath
        : null;
    if (typeof runtimeResolver === 'function') {
        const runtimeBasePath = runtimeResolver('js/script.js');
        if (typeof runtimeBasePath === 'string') {
            return runtimeBasePath.trim();
        }
    }
    if (typeof document === 'undefined' || typeof window === 'undefined') return '';
    const scriptEl = document.querySelector('script[src*="js/script.js"]');
    const scriptSrc = scriptEl?.getAttribute('src');
    if (!scriptSrc) return '';
    try {
        const parsed = new URL(scriptSrc, window.location.href);
        return parsed.pathname
            .replace(/\/js\/script\.js(?:\?.*)?$/i, '')
            .replace(/\/+$/, '');
    } catch (error) {
        return '';
    }
}

const APP_BASE_PATH = getScriptDerivedBasePath();

function withAppBasePath(path) {
    const normalizedPath = String(path || '').trim();
    if (!normalizedPath) return normalizedPath;
    const runtimeWithAppBasePath = typeof window !== 'undefined'
        ? window.CSAtlasRuntime?.withAppBasePath
        : null;
    if (typeof runtimeWithAppBasePath === 'function') {
        return runtimeWithAppBasePath(normalizedPath, APP_BASE_PATH);
    }
    if (!normalizedPath.startsWith('/')) return normalizedPath;
    if (!APP_BASE_PATH) return normalizedPath;
    return `${APP_BASE_PATH}${normalizedPath}`;
}

function resolveAssetUrlWithBase(value) {
    const normalizedValue = String(value || '').trim();
    if (!normalizedValue) return normalizedValue;
    const runtimeResolveAssetUrl = typeof window !== 'undefined'
        ? window.CSAtlasRuntime?.resolveAssetUrl
        : null;
    if (typeof runtimeResolveAssetUrl === 'function') {
        return runtimeResolveAssetUrl(normalizedValue, APP_BASE_PATH);
    }
    if (normalizedValue.startsWith('/')) {
        return withAppBasePath(normalizedValue);
    }
    if (/^(?:[a-zA-Z][a-zA-Z\d+\-.]*:)?\/\//.test(normalizedValue)) {
        return normalizedValue;
    }
    return withAppBasePath(`/${normalizedValue.replace(/^\/+/, '')}`);
}

function isLocalhostRuntime() {
    if (typeof window === 'undefined') return false;
    const hostname = String(window.location.hostname || '').toLowerCase();
    return hostname === 'localhost' || hostname === '127.0.0.1';
}

function buildApiEndpoint(path) {
    const base = getConfiguredApiBaseUrl();
    if (base) return `${base}${path}`;
    return withAppBasePath(path);
}

function normalizeApiBaseUrl(rawUrl) {
    return String(rawUrl || '').trim().replace(/\/+$/, '');
}

function isSecureApiBaseUrl(rawUrl) {
    const base = normalizeApiBaseUrl(rawUrl);
    if (!base) return true;
    try {
        const parsed = new URL(base);
        if (parsed.protocol === 'https:') return true;
        return parsed.protocol === 'http:' && ['localhost', '127.0.0.1'].includes(parsed.hostname);
    } catch (error) {
        return false;
    }
}

function getConfiguredApiBaseUrl() {
    const metaTagBase = typeof document !== 'undefined'
        ? String(document.querySelector('meta[name="csatlas-api-base-url"]')?.getAttribute('content') || '').trim()
        : '';
    const appConfigBase = (typeof window !== 'undefined' && window.__APP_CONFIG?.apiBaseUrl)
        || (typeof window !== 'undefined' && window.__APP_CONFIG?.neonApiBaseUrl)
        || (typeof window !== 'undefined' && window.APP_CONFIG?.apiBaseUrl)
        || (typeof window !== 'undefined' && window.APP_CONFIG?.neonApiBaseUrl)
        || (typeof window !== 'undefined' && window.NEON_API_BASE_URL)
        || '';
    const explicitBase = normalizeApiBaseUrl(PROFILE_SYNC_CONFIG.baseUrl || appConfigBase || metaTagBase || '');
    if (explicitBase) {
        return explicitBase;
    }
    if (typeof window === 'undefined') {
        return '';
    }
    const protocol = String(window.location.protocol || '').toLowerCase();
    const hostname = String(window.location.hostname || '').toLowerCase();
    const port = String(window.location.port || '');
    const localHostnames = new Set(['localhost', '127.0.0.1']);
    if (!localHostnames.has(hostname)) {
        return '';
    }
    if (protocol !== 'http:' && protocol !== 'https:') {
        return '';
    }
    if (port === '3000') {
        return '';
    }
    return normalizeApiBaseUrl(`${protocol}//${hostname}:3000`);
}

function isCrossOriginApiRuntime() {
    if (typeof window === 'undefined') return false;
    const configuredBase = getConfiguredApiBaseUrl();
    if (!configuredBase) return false;
    try {
        const apiOrigin = new URL(configuredBase).origin;
        return apiOrigin.toLowerCase() !== String(window.location.origin || '').toLowerCase();
    } catch (error) {
        return false;
    }
}

function shouldRedirectToCanonicalFrontendForAuth() {
    // Keep auth on the current frontend host.
    return false;
}

function shouldRedirectToApiHostedFrontendForAuth() {
    // Mobile auth redirects to API-hosted frontend are intentionally disabled.
    // Keep users on the primary frontend host and complete auth through API endpoints only.
    return false;
}

function getApiHostedFrontendAuthUrl() {
    if (typeof window === 'undefined') return '';
    const configuredBase = getConfiguredApiBaseUrl();
    if (!configuredBase) return '';
    const search = String(window.location.search || '');
    const hash = String(window.location.hash || '');
    return `${configuredBase}/index.html${search}${hash}`;
}

function maybeRedirectToApiHostedFrontendForAuth() {
    if (!shouldRedirectToApiHostedFrontendForAuth()) return false;
    const targetUrl = getApiHostedFrontendAuthUrl();
    if (!targetUrl) return false;
    setAccountAuthStatus(getStableTranslation('account.auth.redirectingMobile'), 'info');
    showToast(getStableTranslation('account.auth.redirectingMobileToast'), 'info');
    window.location.assign(targetUrl);
    return true;
}

function getCanonicalFrontendAuthUrl() {
    if (typeof window === 'undefined') return 'https://eddyarriaga00.github.io/CS-Course-Atlas/index.html';
    const search = String(window.location.search || '');
    const hash = String(window.location.hash || '');
    return `https://eddyarriaga00.github.io/CS-Course-Atlas/index.html${search}${hash}`;
}

function maybeRedirectToCanonicalFrontendForAuth() {
    if (!shouldRedirectToCanonicalFrontendForAuth()) return false;
    const targetUrl = getCanonicalFrontendAuthUrl();
    setAccountAuthStatus(getStableTranslation('account.auth.redirectingCanonical'), 'info');
    showToast(getStableTranslation('account.auth.redirectingCanonicalToast'), 'info');
    window.location.assign(targetUrl);
    return true;
}

function maybeRedirectToPreferredAuthHost() {
    if (maybeRedirectToApiHostedFrontendForAuth()) return true;
    return maybeRedirectToCanonicalFrontendForAuth();
}

function isApiRuntimeAvailable() {
    const configuredBase = getConfiguredApiBaseUrl();
    if (configuredBase) return isSecureApiBaseUrl(configuredBase);
    if (!isLocalhostRuntime() || typeof window === 'undefined') return false;
    return String(window.location.port || '') === '3000';
}

function getSessionUserFromPayload(payload) {
    const user = payload?.user
        || payload?.data?.user
        || payload?.session?.user
        || payload?.data?.session?.user
        || null;
    const userId = String(
        user?.id
        || user?.user_id
        || payload?.userId
        || payload?.data?.userId
        || ''
    ).trim();
    const userEmail = String(
        user?.email
        || payload?.email
        || payload?.data?.email
        || ''
    ).trim();
    const userUsername = String(
        user?.username
        || user?.name
        || user?.displayName
        || payload?.username
        || payload?.name
        || payload?.data?.username
        || payload?.data?.name
        || ''
    ).trim();
    const userAvatarUrl = String(
        user?.avatarUrl
        || user?.avatar_url
        || payload?.avatarUrl
        || payload?.data?.avatarUrl
        || ''
    ).trim();
    const userSocialHandle = String(
        user?.socialHandle
        || user?.social_handle
        || payload?.socialHandle
        || payload?.data?.socialHandle
        || ''
    ).trim();
    const userSocialStatus = String(
        user?.socialStatus
        || user?.statusText
        || user?.status_text
        || payload?.socialStatus
        || payload?.statusText
        || payload?.data?.socialStatus
        || ''
    ).trim();
    const userMessagingEnabled = parseBooleanLikeClient(
        user?.messagingEnabled
        ?? user?.messaging_enabled
        ?? payload?.messagingEnabled
        ?? payload?.data?.messagingEnabled,
        false
    );
    return {
        userId,
        userEmail,
        userUsername,
        userAvatarUrl,
        userSocialHandle,
        userSocialStatus,
        userMessagingEnabled
    };
}

function resolveSessionProviderFromPayload(payload) {
    const user = payload?.user
        || payload?.data?.user
        || payload?.session?.user
        || payload?.data?.session?.user
        || null;
    const providerCandidates = [
        user?.provider,
        user?.authProvider,
        user?.loginProvider,
        user?.oauthProvider,
        payload?.provider,
        payload?.authProvider,
        payload?.oauthProvider,
        payload?.session?.provider,
        payload?.session?.authProvider,
        payload?.data?.provider,
        payload?.data?.authProvider
    ];
    for (const candidate of providerCandidates) {
        const normalizedProvider = normalizeAuthProviderKey(candidate);
        if (normalizedProvider) {
            return normalizedProvider;
        }
    }
    return '';
}

function resolveSessionAuthenticatedFlag(payload, sessionUser = {}) {
    const inferredFromSessionUser = Boolean(
        sessionUser?.userId
        || sessionUser?.userEmail
        || sessionUser?.userUsername
    );
    const explicitAuthFlagCandidates = [
        payload?.authenticated,
        payload?.isAuthenticated,
        payload?.session?.authenticated,
        payload?.session?.isAuthenticated,
        payload?.data?.authenticated,
        payload?.data?.isAuthenticated,
        payload?.data?.session?.authenticated,
        payload?.data?.session?.isAuthenticated
    ];
    const explicitAuthFlag = explicitAuthFlagCandidates.find((value) => typeof value === 'boolean');
    if (typeof explicitAuthFlag === 'boolean') {
        return explicitAuthFlag;
    }
    return inferredFromSessionUser;
}

function applySessionPayloadToAuthState(sessionPayload, options = {}) {
    const {
        source = 'Session',
        defaultProvider = '',
        rememberSessionToken = null,
        silent = true
    } = options;
    const sessionCsrfToken = String(
        sessionPayload?.csrfToken
        || sessionPayload?.session?.csrfToken
        || sessionPayload?.data?.csrfToken
        || ''
    ).trim();
    const sessionToken = getSessionTokenFromPayload(sessionPayload);
    const sessionUser = getSessionUserFromPayload(sessionPayload);
    const sessionProvider = resolveSessionProviderFromPayload(sessionPayload) || normalizeAuthProviderKey(defaultProvider);
    const isAuthenticated = resolveSessionAuthenticatedFlag(sessionPayload, sessionUser);
    const userLabel = sessionUser.userUsername || sessionUser.userEmail || sessionUser.userId || '';

    if (!isAuthenticated) {
        accountAuthState.isAuthenticated = false;
        accountAuthState.sessionLabel = '';
        setAccountProviderState('', '');
        setCsrfToken('');
        setSessionToken('');
        accountProfile.serverUserId = '';
        clearAuthScopedLocalStorage();
        saveAccountProfile();
        applyAccountProfileToForm();
        updateAccountChip();
        refreshAccountPrimaryAuthButton();
        setAccountAuthStatus(getStableTranslation('auth.status.guest'), 'neutral');
        setAccountSyncState('connected', getStableTranslation('account.sync.notSignedIn'));
        handleInsightsAccessStateChange();
        return {
            isAuthenticated: false,
            userId: '',
            userLabel: ''
        };
    }

    accountAuthState.isAuthenticated = true;
    accountAuthState.sessionLabel = userLabel;
    setAccountProviderState(sessionProvider || 'password', getAuthProviderLabel(sessionProvider || 'password'));
    clearPendingAuthRecoveryState();

    if (sessionCsrfToken) {
        setCsrfToken(sessionCsrfToken);
    }

    if (sessionToken) {
        const shouldRemember = typeof rememberSessionToken === 'boolean'
            ? rememberSessionToken
            : Boolean(accountAuthState.rememberMe);
        setSessionToken(sessionToken, { remember: shouldRemember });
    } else if (!getSessionToken()) {
        setSessionToken('');
    }

    if (sessionUser.userId) {
        accountProfile.serverUserId = sessionUser.userId;
    }
    if (sessionUser.userUsername) {
        accountProfile.username = sessionUser.userUsername;
        accountProfile.name = sessionUser.userUsername;
    }
    if (sessionUser.userEmail) {
        accountProfile.email = sessionUser.userEmail;
    }
    if (sessionUser.userAvatarUrl) {
        accountProfile.avatarUrl = sanitizeAvatarUrlClient(sessionUser.userAvatarUrl);
    }
    if (sessionUser.userSocialHandle) {
        accountProfile.socialHandle = sanitizeSocialHandleClient(sessionUser.userSocialHandle);
    }
    if (sessionUser.userSocialStatus) {
        accountProfile.socialStatus = sanitizeSocialStatusClient(sessionUser.userSocialStatus);
    }
    if (typeof sessionUser.userMessagingEnabled === 'boolean') {
        accountProfile.messagingEnabled = sessionUser.userMessagingEnabled;
    }
    const resolvedGoal = String(
        sessionPayload?.user?.goal
        || sessionPayload?.session?.user?.goal
        || sessionPayload?.data?.user?.goal
        || ''
    ).trim();
    if (resolvedGoal) {
        accountProfile.goal = resolvedGoal;
    }

    saveAccountProfile();
    applyAccountProfileToForm();
    updateAccountChip();
    refreshAccountPrimaryAuthButton();
    setAccountAuthStatus(
        getStableTranslation('account.auth.sessionStatusAuthenticatedAs', { name: userLabel || getStableTranslation('account.profile.displayName.guest') }),
        'success'
    );
    setAccountSyncState('connected', `${source} active${userLabel ? ` for ${userLabel}` : ''}`);
    handleInsightsAccessStateChange();
    if (!silent && userLabel) {
        showToast(getStableTranslation('account.auth.sessionStatusSignedIn', { name: userLabel }), 'success');
    }
    return {
        isAuthenticated: true,
        userId: String(sessionUser.userId || accountProfile.serverUserId || '').trim(),
        userLabel
    };
}

